257 // Returns false if the function should not be considered for hot-cold split
258 // optimization.
259 bool HotColdSplitting::shouldOutlineFrom(const Function &F) const {
260   if (F.hasFnAttribute(Attribute::AlwaysInline))
261     return false;
262 
263   if (F.hasFnAttribute(Attribute::NoInline))
264     return false;
265 
266   // A function marked `noreturn` may contain unreachable terminators: these
267   // should not be considered cold, as the function may be a trampoline.
268   if (F.hasFnAttribute(Attribute::NoReturn))
269     return false;
270 
271   if (F.hasFnAttribute(Attribute::SanitizeAddress) ||
272       F.hasFnAttribute(Attribute::SanitizeHWAddress) ||
273       F.hasFnAttribute(Attribute::SanitizeThread) ||
274       F.hasFnAttribute(Attribute::SanitizeMemory))
275     return false;
276 
277   // Do not outline scoped EH personality functions.
278   if (F.hasPersonalityFn())
279     if (isScopedEHPersonality(classifyEHPersonality(F.getPersonalityFn())))
280       return false;
281 
282   // Do not split functions marked with the nooutline attribute.
283   if (F.hasFnAttribute("nooutline")) {
284     ++NumFunctionsSkippedByNoOutlineAttr;
285     return false;
286   }
287 
288   return true;
289 }
