291 /// Get the benefit score of outlining \p Region.
292 static InstructionCost getOutliningBenefit(ArrayRef<BasicBlock *> Region,
293                                            TargetTransformInfo &TTI) {
294   // Sum up the code size costs of non-terminator instructions. Tight coupling
295   // with \ref getOutliningPenalty is needed to model the costs of terminators.
296   InstructionCost Benefit = 0;
297   for (BasicBlock *BB : Region)
298     for (Instruction &I : BB->instructionsWithoutDebug())
299       if (&I != BB->getTerminator())
300         Benefit +=
301             TTI.getInstructionCost(&I, TargetTransformInfo::TCK_CodeSize);
302 
303   return Benefit;
304 }
