306 /// Get the penalty score for outlining \p Region.
307 static int getOutliningPenalty(ArrayRef<BasicBlock *> Region,
308                                unsigned NumInputs, unsigned NumOutputs) {
309   int Penalty = SplittingThreshold;
310   LLVM_DEBUG(dbgs() << "Applying penalty for splitting: " << Penalty << "\n");
311 
312   // If the splitting threshold is set at or below zero, skip the usual
313   // profitability check.
314   if (SplittingThreshold <= 0)
315     return Penalty;
316 
317   // Find the number of distinct exit blocks for the region. Use a conservative
318   // check to determine whether control returns from the region.
319   bool NoBlocksReturn = true;
320   SmallPtrSet<BasicBlock *, 2> SuccsOutsideRegion;
321   for (BasicBlock *BB : Region) {
322     // If a block has no successors, only assume it does not return if it's
323     // unreachable.
324     if (succ_empty(BB)) {
325       NoBlocksReturn &= isa<UnreachableInst>(BB->getTerminator());
326       continue;
327     }
328 
329     for (BasicBlock *SuccBB : successors(BB)) {
330       if (!is_contained(Region, SuccBB)) {
331         NoBlocksReturn = false;
332         SuccsOutsideRegion.insert(SuccBB);
333       }
334     }
335   }
336 
337   // Count the number of phis in exit blocks with >= 2 incoming values from the
338   // outlining region. These phis are split (\ref severSplitPHINodesOfExits),
339   // and new outputs are created to supply the split phis. CodeExtractor can't
340   // report these new outputs until extraction begins, but it's important to
341   // factor the cost of the outputs into the cost calculation.
342   unsigned NumSplitExitPhis = 0;
343   for (BasicBlock *ExitBB : SuccsOutsideRegion) {
344     for (PHINode &PN : ExitBB->phis()) {
345       // Find all incoming values from the outlining region.
346       int NumIncomingVals = 0;
347       for (unsigned i = 0; i < PN.getNumIncomingValues(); ++i)
348         if (llvm::is_contained(Region, PN.getIncomingBlock(i))) {
349           ++NumIncomingVals;
350           if (NumIncomingVals > 1) {
351             ++NumSplitExitPhis;
352             break;
353           }
354         }
355     }
356   }
357 
358   // Apply a penalty for calling the split function. Factor in the cost of
359   // materializing all of the parameters.
360   int NumOutputsAndSplitPhis = NumOutputs + NumSplitExitPhis;
361   int NumParams = NumInputs + NumOutputsAndSplitPhis;
362   if (NumParams > MaxParametersForSplit) {
363     LLVM_DEBUG(dbgs() << NumInputs << " inputs and " << NumOutputsAndSplitPhis
364                       << " outputs exceeds parameter limit ("
365                       << MaxParametersForSplit << ")\n");
366     return std::numeric_limits<int>::max();
367   }
368   const int CostForArgMaterialization = 2 * TargetTransformInfo::TCC_Basic;
369   LLVM_DEBUG(dbgs() << "Applying penalty for: " << NumParams << " params\n");
370   Penalty += CostForArgMaterialization * NumParams;
371 
372   // Apply the typical code size cost for an output alloca and its associated
373   // reload in the caller. Also penalize the associated store in the callee.
374   LLVM_DEBUG(dbgs() << "Applying penalty for: " << NumOutputsAndSplitPhis
375                     << " outputs/split phis\n");
376   const int CostForRegionOutput = 3 * TargetTransformInfo::TCC_Basic;
377   Penalty += CostForRegionOutput * NumOutputsAndSplitPhis;
378 
379   // Apply a `noreturn` bonus.
380   if (NoBlocksReturn) {
381     LLVM_DEBUG(dbgs() << "Applying bonus for: " << Region.size()
382                       << " non-returning terminators\n");
383     Penalty -= Region.size();
384   }
385 
386   // Apply a penalty for having more than one successor outside of the region.
387   // This penalty accounts for the switch needed in the caller.
388   if (SuccsOutsideRegion.size() > 1) {
389     LLVM_DEBUG(dbgs() << "Applying penalty for: " << SuccsOutsideRegion.size()
390                       << " non-region successors\n");
391     Penalty += (SuccsOutsideRegion.size() - 1) * TargetTransformInfo::TCC_Basic;
392   }
393 
394   return Penalty;
395 }
