397 // Determine if it is beneficial to split the \p Region.
398 bool HotColdSplitting::isSplittingBeneficial(CodeExtractor &CE,
399                                              const BlockSequence &Region,
400                                              TargetTransformInfo &TTI) {
401   assert(!Region.empty());
402 
403   // Perform a simple cost/benefit analysis to decide whether or not to permit
404   // splitting.
405   SetVector<Value *> Inputs, Outputs, Sinks;
406   CE.findInputsOutputs(Inputs, Outputs, Sinks);
407   InstructionCost OutliningBenefit = getOutliningBenefit(Region, TTI);
408   int OutliningPenalty =
409       getOutliningPenalty(Region, Inputs.size(), Outputs.size());
410   LLVM_DEBUG(dbgs() << "Split profitability: benefit = " << OutliningBenefit
411                     << ", penalty = " << OutliningPenalty << "\n");
412   if (!OutliningBenefit.isValid() || OutliningBenefit <= OutliningPenalty)
413     return false;
414 
415   return true;
416 }
