418 // Split the single \p EntryPoint cold region. \p CE is the region code
419 // extractor.
420 Function *HotColdSplitting::extractColdRegion(
421     BasicBlock &EntryPoint, CodeExtractor &CE,
422     const CodeExtractorAnalysisCache &CEAC, BlockFrequencyInfo *BFI,
423     TargetTransformInfo &TTI, OptimizationRemarkEmitter &ORE) {
424   Function *OrigF = EntryPoint.getParent();
425   if (Function *OutF = CE.extractCodeRegion(CEAC)) {
426     User *U = *OutF->user_begin();
427     CallInst *CI = cast<CallInst>(U);
428     NumColdRegionsOutlined++;
429     if (TTI.useColdCCForColdCall(*OutF)) {
430       OutF->setCallingConv(CallingConv::Cold);
431       CI->setCallingConv(CallingConv::Cold);
432     }
433     CI->setIsNoInline();
434 
435     if (EnableColdSection)
436       OutF->setSection(ColdSectionName);
437     else {
438       if (OrigF->hasSection())
439         OutF->setSection(OrigF->getSection());
440     }
441 
442     markFunctionCold(*OutF, BFI != nullptr);
443 
444     LLVM_DEBUG(llvm::dbgs() << "Outlined Region: " << *OutF);
445     ORE.emit([&]() {
446       return OptimizationRemark(DEBUG_TYPE, "HotColdSplit",
447                                 &*EntryPoint.begin())
448              << ore::NV("Original", OrigF) << " split cold code into "
449              << ore::NV("Split", OutF);
450     });
451     return OutF;
452   }
453 
454   ORE.emit([&]() {
455     return OptimizationRemarkMissed(DEBUG_TYPE, "ExtractFailed",
456                                     &*EntryPoint.begin())
457            << "Failed to extract region at block "
458            << ore::NV("Block", &EntryPoint);
459   });
460   return nullptr;
461 }
