466 namespace {
467 /// A maximal outlining region. This contains all blocks post-dominated by a
468 /// sink block, the sink block itself, and all blocks dominated by the sink.
469 /// If sink-predecessors and sink-successors cannot be extracted in one region,
470 /// the static constructor returns a list of suitable extraction regions.
471 class OutliningRegion {
472   /// A list of (block, score) pairs. A block's score is non-zero iff it's a
473   /// viable sub-region entry point. Blocks with higher scores are better entry
474   /// points (i.e. they are more distant ancestors of the sink block).
475   SmallVector<BlockTy, 0> Blocks = {};
476 
477   /// The suggested entry point into the region. If the region has multiple
478   /// entry points, all blocks within the region may not be reachable from this
479   /// entry point.
480   BasicBlock *SuggestedEntryPoint = nullptr;
481 
482   /// Whether the entire function is cold.
483   bool EntireFunctionCold = false;
484 
485   /// If \p BB is a viable entry point, return \p Score. Return 0 otherwise.
486   static unsigned getEntryPointScore(BasicBlock &BB, unsigned Score) {
487     return mayExtractBlock(BB) ? Score : 0;
488   }
489 
490   /// These scores should be lower than the score for predecessor blocks,
491   /// because regions starting at predecessor blocks are typically larger.
492   static constexpr unsigned ScoreForSuccBlock = 1;
493   static constexpr unsigned ScoreForSinkBlock = 1;
494 
495   OutliningRegion(const OutliningRegion &) = delete;
496   OutliningRegion &operator=(const OutliningRegion &) = delete;
497 
498 public:
499   OutliningRegion() = default;
